const now=new Date();const hcm=new Date(Date.now()+7*60*60*1000);
const y=new Date(hcm.getTime()-24*60*60*1000);
const dd=String(y.getUTCDate()).padStart(2,'0');const mm=String(y.getUTCMonth()+1).padStart(2,'0');const yyyy=y.getUTCFullYear();
const sd=$getWorkflowStaticData('global');const spaId=sd.spaId||'default-spa';
return [{json:{runDate:y.toISOString(),isoDate:yyyy+'-'+mm+'-'+dd,dateStr:dd+'/'+mm+'/'+yyyy,spaId}}];

const isoDate = $('Code - Date Setup').first().json.isoDate;
const logRows = $('DT - Read Chat Logs').all();
const bookRows = $('DT - Read Bookings').all();
const logs = logRows.filter(r => (r.json.created_at||'').includes(isoDate));
const books = bookRows.filter(r => (r.json.created_at||'').includes(isoDate));
if(logs.length===0&&books.length===0)return [{json:{totalMessages:0,newBookings:0,confirmed:0,pending:0,completed:0,cancelled:0,conversionRate:'0.0',topServices:[],complaints:0,isEmpty:true}}];
const totalMsg=logs.length;const newBk=books.length;
const confirmed=books.filter(r=>r.json.status==='Đã xác确认').length;
const pending=books.filter(r=>r.json.status==='Mới đặt').length;
const completed=books.filter(r=>r.json.status==='Hoàn thành').length;
const cancelled=books.filter(r=>r.json.status==='Đã hủy').length;
const conv=totalMsg>0?(newBk/totalMsg*100).toFixed(1):'0.0';
const svcMap={};books.forEach(r=>{const s=r.json.service||'Khác';svcMap[s]=(svcMap[s]||0)+1;});
const topSvc=Object.entries(svcMap).sort((a,b)=>b[1]-a[1]).slice(0,5).map(([n,c])=>({name:n,count:c}));
const complaints=logs.filter(r=>(r.json.category||'').toLowerCase().match(/phản ánh|complaint/)).length;
return [{json:{totalMessages:totalMsg,newBookings:newBk,confirmed,pending,completed,cancelled,conversionRate:conv,topServices:topSvc,complaints,isEmpty:false}}];

